    80‚Üífunction TmsContent() {
    81‚Üí  const [applicationName, setApplicationName] = useState<string>('');
    82‚Üí  const [availableApplications, setAvailableApplications] = useState<string[]>([]);
    83‚Üí  const [availableLocales, setAvailableLocales] = useState<string[]>([]);
    84‚Üí  // Unified structure: single TranslationsModel where each translation has all locales
    85‚Üí  const [unifiedTranslations, setUnifiedTranslations] = useState<TranslationsModel | null>(null);
    86‚Üí  const [expandedComponents, setExpandedComponents] = useState<Set<string>>(new Set());
    87‚Üí  const [loading, setLoading] = useState(true);
    88‚Üí  const [saving, setSaving] = useState(false);
    89‚Üí  const [error, setError] = useState('');
    90‚Üí  
    91‚Üí  // Dialog states
    92‚Üí  const [createAppDialogOpen, setCreateAppDialogOpen] = useState(false);
    93‚Üí  const [createComponentDialogOpen, setCreateComponentDialogOpen] = useState(false);
    94‚Üí  const [createTranslationDialogOpen, setCreateTranslationDialogOpen] = useState(false);
    95‚Üí  const [newAppName, setNewAppName] = useState('');
    96‚Üí  const [newComponentName, setNewComponentName] = useState('');
    97‚Üí  const [newComponentDescription, setNewComponentDescription] = useState('');
    98‚Üí  const [newComponentPath, setNewComponentPath] = useState<string[]>([]);
    99‚Üí  const [newTranslationName, setNewTranslationName] = useState('');
   100‚Üí  const [newTranslationDescription, setNewTranslationDescription] = useState('');
   101‚Üí  const [newTranslationPath, setNewTranslationPath] = useState<string[]>([]);
   102‚Üí  const [selectedLocales, setSelectedLocales] = useState<string[]>(['en']);
   103‚Üí
   104‚Üí  const loadApplications = async () => {
   105‚Üí    try {
   106‚Üí      const apps = await apiClient.getAllApplications();
   107‚Üí      setAvailableApplications(apps);
   108‚Üí      if (!applicationName && apps.length > 0) {
   109‚Üí        setApplicationName(apps[0]);
   110‚Üí      }
   111‚Üí    } catch (err) {
   112‚Üí      console.error('Failed to load applications:', err);
   113‚Üí    }
   114‚Üí  };
   115‚Üí
   116‚Üí  const loadLocales = async () => {
   117‚Üí    try {
   118‚Üí      const locales = await apiClient.getAllLocales();
   119‚Üí      setAvailableLocales(locales);
   120‚Üí    } catch (err) {
   121‚Üí      console.error('Failed to load locales:', err);
   122‚Üí    }
   123‚Üí  };
   124‚Üí
   125‚Üí  // Merge translations from all locales into unified structure
   126‚Üí  const mergeTranslations = (translationsByLocale: Map<string, TranslationsModel>): TranslationsModel | null => {
   127‚Üí    if (translationsByLocale.size === 0) return null;
   128‚Üí
   129‚Üí    const firstTranslation = Array.from(translationsByLocale.values())[0];
   130‚Üí    if (!firstTranslation) return null;
   131‚Üí
   132‚Üí    const merged: TranslationsModel = {
   133‚Üí      applicationName: firstTranslation.applicationName,
   134‚Üí      components: [],
   135‚Üí      version: firstTranslation.version,
   136‚Üí    };
   137‚Üí
   138‚Üí    // Helper to merge components recursively
   139‚Üí    const mergeComponents = (componentsByLocale: TranslationComponent[][]): TranslationComponent[] => {
   140‚Üí      if (componentsByLocale.length === 0) return [];
   141‚Üí
   142‚Üí      const componentMap = new Map<string, TranslationComponent>();
   143‚Üí
   144‚Üí      componentsByLocale.forEach((components) => {
   145‚Üí        const processComponent = (comp: TranslationComponent, path: string[] = []) => {
   146‚Üí          const key = [...path, comp.name].join('.');
   147‚Üí          
   148‚Üí          if (!componentMap.has(key)) {
   149‚Üí            componentMap.set(key, {
   150‚Üí              name: comp.name,
   151‚Üí              description: comp.description,
   152‚Üí              components: [],
   153‚Üí              translations: [],
   154‚Üí            });
   155‚Üí          }
   156‚Üí
   157‚Üí          const mergedComp = componentMap.get(key)!;
   158‚Üí
   159‚Üí          // Merge translations
   160‚Üí          if (comp.translations) {
   161‚Üí            comp.translations.forEach((trans) => {
   162‚Üí              let mergedTrans = mergedComp.translations?.find(t => t.name === trans.name);
   163‚Üí              
   164‚Üí              if (!mergedTrans) {
   165‚Üí                mergedTrans = {
   166‚Üí                  name: trans.name,
   167‚Üí                  description: trans.description,
   168‚Üí                  version: trans.version,
   169‚Üí                  locales: [],
   170‚Üí                };
   171‚Üí                mergedComp.translations = [...(mergedComp.translations || []), mergedTrans];
   172‚Üí              }
   173‚Üí
   174‚Üí              // Merge all locales from this translation
   175‚Üí              trans.locales.forEach((locale) => {
   176‚Üí                const existingIndex = mergedTrans!.locales.findIndex(l => l.code === locale.code);
   177‚Üí                if (existingIndex >= 0) {
   178‚Üí                  // Update value
   179‚Üí                  mergedTrans!.locales[existingIndex] = { code: locale.code, value: locale.value };
   180‚Üí                } else {
   181‚Üí                  // Add new locale
   182‚Üí                  mergedTrans!.locales.push({ code: locale.code, value: locale.value });
   183‚Üí                }
   184‚Üí              });
   185‚Üí            });
   186‚Üí          }
   187‚Üí
   188‚Üí          // Process nested components
   189‚Üí          if (comp.components) {
   190‚Üí            comp.components.forEach(subComp => processComponent(subComp, [...path, comp.name]));
   191‚Üí          }
   192‚Üí        };
   193‚Üí
   194‚Üí        components.forEach(comp => processComponent(comp));
   195‚Üí      });
   196‚Üí
   197‚Üí      // Build tree structure from map
   198‚Üí      const buildTree = (path: string[] = []): TranslationComponent[] => {
   199‚Üí        const result: TranslationComponent[] = [];
   200‚Üí        const pathStr = path.join('.');
   201‚Üí        
   202‚Üí        componentMap.forEach((comp, key) => {
   203‚Üí          const compPath = key.split('.');
   204‚Üí          const parentPath = compPath.slice(0, -1);
   205‚Üí          const parentPathStr = parentPath.join('.');
   206‚Üí          
   207‚Üí          if (parentPathStr === pathStr) {
   208‚Üí            result.push({
   209‚Üí              ...comp,
   210‚Üí              components: buildTree(compPath),
   211‚Üí            });
   212‚Üí          }
   213‚Üí        });
   214‚Üí
   215‚Üí        return result;
   216‚Üí      };
   217‚Üí
   218‚Üí      return buildTree();
   219‚Üí    };
   220‚Üí
   221‚Üí    const allComponents = Array.from(translationsByLocale.values()).map(t => t.components);
   222‚Üí    merged.components = mergeComponents(allComponents);
   223‚Üí    return merged;
   224‚Üí  };
   225‚Üí
   226‚Üí  const loadTranslations = async () => {
   227‚Üí    if (!applicationName) {
   228‚Üí      setLoading(false);
   229‚Üí      return;
   230‚Üí    }
   231‚Üí
   232‚Üí    setLoading(true);
   233‚Üí    setError('');
   234‚Üí    try {
   235‚Üí      const translationsByLocale = new Map<string, TranslationsModel>();
   236‚Üí      
   237‚Üí      // Load all locales
   238‚Üí      await Promise.all(
   239‚Üí        availableLocales.map(async (locale) => {
   240‚Üí          try {
   241‚Üí            const data = await apiClient.getTranslations(locale, applicationName);
   242‚Üí            translationsByLocale.set(locale, data);
   243‚Üí          } catch (err) {
   244‚Üí            console.error(`Failed to load translations for locale ${locale}:`, err);
   245‚Üí          }
   246‚Üí        })
   247‚Üí      );
   248‚Üí
   249‚Üí      // Merge into unified structure
   250‚Üí      const merged = mergeTranslations(translationsByLocale);
   251‚Üí      setUnifiedTranslations(merged);
   252‚Üí    } catch (err) {
   253‚Üí      setError(
   254‚Üí        err instanceof Error ? err.message : 'Failed to load translations',
   255‚Üí      );
   256‚Üí    } finally {
   257‚Üí      setLoading(false);
   258‚Üí    }
   259‚Üí  };
   260‚Üí
   261‚Üí  useEffect(() => {
   262‚Üí    loadApplications();
   263‚Üí    loadLocales();
   264‚Üí  }, []);
   265‚Üí
   266‚Üí  useEffect(() => {
   267‚Üí    if (availableLocales.length > 0) {
   268‚Üí      loadTranslations();
   269‚Üí    }
   270‚Üí  }, [applicationName, availableLocales]);
   271‚Üí
   272‚Üí  // Split unified structure back into per-locale structures for API
   273‚Üí  const splitByLocale = (unified: TranslationsModel): Map<string, TranslationsModel> => {
   274‚Üí    const result = new Map<string, TranslationsModel>();
   275‚Üí    const allLocales = new Set<string>();
   276‚Üí
   277‚Üí    // Collect all locales from all translations
   278‚Üí    const collectLocales = (components: TranslationComponent[]) => {
   279‚Üí      components.forEach(comp => {
   280‚Üí        if (comp.translations) {
   281‚Üí          comp.translations.forEach(trans => {
   282‚Üí            trans.locales.forEach(locale => {
   283‚Üí              allLocales.add(locale.code);
   284‚Üí            });
   285‚Üí          });
   286‚Üí        }
   287‚Üí        if (comp.components) {
   288‚Üí          collectLocales(comp.components);
   289‚Üí        }
   290‚Üí      });
   291‚Üí    };
   292‚Üí
   293‚Üí    collectLocales(unified.components);
   294‚Üí
   295‚Üí    // Create structure for each locale
   296‚Üí    allLocales.forEach(localeCode => {
   297‚Üí      const splitComponent = (comp: TranslationComponent): TranslationComponent => {
   298‚Üí        const splitTrans: TranslationItem[] = [];
   299‚Üí        
   300‚Üí        if (comp.translations) {
   301‚Üí          comp.translations.forEach(trans => {
   302‚Üí            const localeItem = trans.locales.find(l => l.code === localeCode);
   303‚Üí            if (localeItem) {
   304‚Üí              splitTrans.push({
   305‚Üí                name: trans.name,
   306‚Üí                description: trans.description,
   307‚Üí                version: trans.version,
   308‚Üí                locales: [localeItem],
   309‚Üí              });
   310‚Üí            }
   311‚Üí          });
   312‚Üí        }
   313‚Üí
   314‚Üí        return {
   315‚Üí          name: comp.name,
   316‚Üí          description: comp.description,
   317‚Üí          components: comp.components?.map(splitComponent),
   318‚Üí          translations: splitTrans.length > 0 ? splitTrans : undefined,
   319‚Üí        };
   320‚Üí      };
   321‚Üí
   322‚Üí      result.set(localeCode, {
   323‚Üí        applicationName: unified.applicationName,
   324‚Üí        components: unified.components.map(splitComponent),
   325‚Üí        version: unified.version,
   326‚Üí      });
   327‚Üí    });
   328‚Üí
   329‚Üí    return result;
   330‚Üí  };
   331‚Üí
   332‚Üí  const updateTranslationValue = (
   333‚Üí    componentPath: string[],
   334‚Üí    translationName: string,
   335‚Üí    localeCode: string,
   336‚Üí    value: string,
   337‚Üí  ) => {
   338‚Üí    if (!unifiedTranslations) return;
   339‚Üí
   340‚Üí    setUnifiedTranslations((prev) => {
   341‚Üí      if (!prev) return prev;
   342‚Üí
   343‚Üí      const updateInComponents = (components: TranslationComponent[], path: string[]): TranslationComponent[] => {
   344‚Üí        if (path.length === 0) {
   345‚Üí          return components.map(comp => {
   346‚Üí            if (!comp.translations) return comp;
   347‚Üí            
   348‚Üí            return {
   349‚Üí              ...comp,
   350‚Üí              translations: comp.translations.map(trans => {
   351‚Üí                if (trans.name !== translationName) return trans;
   352‚Üí                
   353‚Üí                const localeIndex = trans.locales.findIndex(l => l.code === localeCode);
   354‚Üí                if (localeIndex >= 0) {
   355‚Üí                  return {
   356‚Üí                    ...trans,
   357‚Üí                    locales: trans.locales.map((loc, idx) => 
   358‚Üí                      idx === localeIndex ? { ...loc, value } : loc
   359‚Üí                    ),
   360‚Üí                  };
   361‚Üí                } else {
   362‚Üí                  return {
   363‚Üí                    ...trans,
   364‚Üí                    locales: [...trans.locales, { code: localeCode, value }],
   365‚Üí                  };
   366‚Üí                }
   367‚Üí              }),
   368‚Üí            };
   369‚Üí          });
   370‚Üí        }
   371‚Üí
   372‚Üí        const [current, ...rest] = path;
   373‚Üí        return components.map(comp => {
   374‚Üí          if (comp.name !== current) return comp;
   375‚Üí
   376‚Üí          return {
   377‚Üí            ...comp,
   378‚Üí            components: comp.components ? updateInComponents(comp.components, rest) : undefined,
   379‚Üí            translations: rest.length === 0 && comp.translations
   380‚Üí              ? comp.translations.map(trans => {
   381‚Üí                  if (trans.name !== translationName) return trans;
   382‚Üí                  
   383‚Üí                  const localeIndex = trans.locales.findIndex(l => l.code === localeCode);
   384‚Üí                  if (localeIndex >= 0) {
   385‚Üí                    return {
   386‚Üí                      ...trans,
   387‚Üí                      locales: trans.locales.map((loc, idx) => 
   388‚Üí                        idx === localeIndex ? { ...loc, value } : loc
   389‚Üí                      ),
   390‚Üí                    };
   391‚Üí                  } else {
   392‚Üí                    return {
   393‚Üí                      ...trans,
   394‚Üí                      locales: [...trans.locales, { code: localeCode, value }],
   395‚Üí                    };
   396‚Üí                  }
   397‚Üí                })
   398‚Üí              : comp.translations,
   399‚Üí          };
   400‚Üí        });
   401‚Üí      };
   402‚Üí
   403‚Üí      return {
   404‚Üí        ...prev,
   405‚Üí        components: updateInComponents(prev.components, componentPath),
   406‚Üí      };
   407‚Üí    });
   408‚Üí  };
   409‚Üí
   410‚Üí  const addLocaleToTranslation = (
   411‚Üí    componentPath: string[],
   412‚Üí    translationName: string,
   413‚Üí    localeCode: string,
   414‚Üí  ) => {
   415‚Üí    if (!unifiedTranslations) return;
   416‚Üí
   417‚Üí    setUnifiedTranslations((prev) => {
   418‚Üí      if (!prev) return prev;
   419‚Üí
   420‚Üí      const addLocaleInComponents = (components: TranslationComponent[], path: string[]): TranslationComponent[] => {
   421‚Üí        if (path.length === 0) {
   422‚Üí          return components.map(comp => {
   423‚Üí            if (!comp.translations) return comp;
   424‚Üí            
   425‚Üí            return {
   426‚Üí              ...comp,
   427‚Üí              translations: comp.translations.map(trans => {
   428‚Üí                if (trans.name === translationName) {
   429‚Üí                  const hasLocale = trans.locales.some(l => l.code === localeCode);
   430‚Üí                  if (!hasLocale) {
   431‚Üí                    return {
   432‚Üí                      ...trans,
   433‚Üí                      locales: [...trans.locales, { code: localeCode, value: '' }],
   434‚Üí                    };
   435‚Üí                  }
   436‚Üí                }
   437‚Üí                return trans;
   438‚Üí              }),
   439‚Üí            };
   440‚Üí          });
   441‚Üí        }
