     6‚Üí
     7‚Üíexport class TranslationsModel {
     8‚Üí  applicationName: string;
     9‚Üí  components: TranslationComponentDto[];
    10‚Üí  version: number;
    11‚Üí}
    12‚Üí
    13‚Üíexport class TranslationsMapper {
    14‚Üí  constructor(private readonly translations: TranslationsModel) {}
    15‚Üí
    16‚Üí  /**
    17‚Üí   * Maps the nested translation structure to a flat dot-notation object
    18‚Üí   * @param locale - BCP-47 locale code (e.g., 'en', 'en-US', 'ru')
    19‚Üí   * @returns Record with keys like "applicationName.component.subcomponent.translationName"
    20‚Üí   */
    21‚Üí  mapToFlatObject(locale: string): Record<string, string> {
    22‚Üí    const result: Record<string, string> = {};
    23‚Üí
    24‚Üí    const processComponent = (
    25‚Üí      component: TranslationComponentDto,
    26‚Üí      path: string[],
    27‚Üí    ): void => {
    28‚Üí      const currentPath = [...path, component.name];
    29‚Üí
    30‚Üí      // Process translations in this component
    31‚Üí      if (component.translations) {
    32‚Üí        for (const translation of component.translations) {
    33‚Üí          const localeItem = translation.locales.find(
    34‚Üí            (loc) => loc.code === locale,
    35‚Üí          );
    36‚Üí          if (localeItem) {
    37‚Üí            const key = [
    38‚Üí              this.translations.applicationName,
    39‚Üí              ...currentPath,
    40‚Üí              translation.name,
    41‚Üí            ].join('.');
    42‚Üí            result[key] = localeItem.value;
    43‚Üí          }
    44‚Üí        }
    45‚Üí      }
    46‚Üí
    47‚Üí      // Recursively process nested components
    48‚Üí      if (component.components) {
    49‚Üí        for (const nestedComponent of component.components) {
    50‚Üí          processComponent(nestedComponent, currentPath);
    51‚Üí        }
    52‚Üí      }
    53‚Üí    };
    54‚Üí
    55‚Üí    // Process all root components
    56‚Üí    for (const component of this.translations.components) {
    57‚Üí      processComponent(component, []);
    58‚Üí    }
    59‚Üí
    60‚Üí    return result;
    61‚Üí  }
    62‚Üí
    63‚Üí  /**
    64‚Üí   * Gets all translation items that have a translation for the specified locale
    65‚Üí   * @param locale - BCP-47 locale code
    66‚Üí   * @returns Array of TranslationItem that have a translation for the locale
    67‚Üí   */
    68‚Üí  getAllTranslationsByLocale(locale: string): TranslationItemDto[] {
    69‚Üí    const result: TranslationItemDto[] = [];
    70‚Üí
    71‚Üí    const processComponent = (component: TranslationComponentDto): void => {
    72‚Üí      if (component.translations) {
    73‚Üí        for (const translation of component.translations) {
    74‚Üí          if (translation.locales.some((loc) => loc.code === locale)) {
    75‚Üí            result.push(translation);
    76‚Üí          }
    77‚Üí        }
    78‚Üí      }
    79‚Üí
    80‚Üí      if (component.components) {
    81‚Üí        for (const nestedComponent of component.components) {
    82‚Üí          processComponent(nestedComponent);
    83‚Üí        }
    84‚Üí      }
    85‚Üí    };
    86‚Üí
    87‚Üí    for (const component of this.translations.components) {
    88‚Üí      processComponent(component);
    89‚Üí    }
    90‚Üí
    91‚Üí    return result;
    92‚Üí  }
    93‚Üí
    94‚Üí  /**
    95‚Üí   * Gets a specific translation value by path and locale
    96‚Üí   * @param path - Dot-separated path (e.g., "sidebar.menu.item1")
    97‚Üí   * @param locale - BCP-47 locale code
    98‚Üí   * @returns Translation value or undefined if not found
    99‚Üí   */
   100‚Üí  getTranslation(path: string, locale: string): string | undefined {
   101‚Üí    const flatObject = this.mapToFlatObject(locale);
   102‚Üí    const fullPath = `${this.translations.applicationName}.${path}`;
   103‚Üí    return flatObject[fullPath];
   104‚Üí  }
   105‚Üí}
   106‚Üí
   107‚Üíconst translations: TranslationsModelDto = {
   108‚Üí  applicationName: 'myApp',
   109‚Üí  version: 1,
   110‚Üí  components: [
   111‚Üí    {
   112‚Üí      name: 'sidebar',
   113‚Üí      components: [
   114‚Üí        {
   115‚Üí          name: 'menu',
   116‚Üí          translations: [
   117‚Üí            {
